import{_ as l,o,c as a,ae as r}from"./chunks/framework.Czhw_PXq.js";const i="/images/lilu-book/00007.jpeg",b=JSON.parse('{"title":"《文明、现代化、价值投资与中国》第4讲：价值投资在中国的展望","description":"价值投资的四大核心理念：为什么这是一条康庄大道？为什么走的人却很少？","frontmatter":{"title":"《文明、现代化、价值投资与中国》第4讲：价值投资在中国的展望","description":"价值投资的四大核心理念：为什么这是一条康庄大道？为什么走的人却很少？","pubDate":"2026-05-16","heroImage":"/images/lilu-book/00010.jpeg"},"headers":[],"relativePath":"posts/lilu-book-04.md","filePath":"posts/lilu-book-04.md"}'),e={name:"posts/lilu-book-04.md"};function n(s,t,d,h,g,p){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="第4讲-价值投资在中国的展望" tabindex="-1">第4讲：价值投资在中国的展望 <a class="header-anchor" href="#第4讲-价值投资在中国的展望" aria-label="Permalink to &quot;第4讲：价值投资在中国的展望&quot;">​</a></h1><blockquote><p>投资的大道上却根本没人，交通一点都不堵塞，冷冷清清。人都去哪了呢？旁门左道上车水马龙！</p></blockquote><h2 id="引言-为什么开这门课" tabindex="-1">引言：为什么开这门课 <a class="header-anchor" href="#引言-为什么开这门课" aria-label="Permalink to &quot;引言：为什么开这门课&quot;">​</a></h2><p>2015年10月，李录在北京大学光华管理学院开设了国内第一门价值投资课程。</p><p><strong>背景</strong>：</p><ul><li>刚经历股灾（2015年6-8月）</li><li>市场从牛市到熊市只用了3个月</li><li>无数投资者损失惨重</li><li>价值投资理念在中国几乎空白</li></ul><p><strong>李录的四个核心问题</strong>：</p><ol><li>资产管理行业的独特性及其道德底线要求</li><li>从长期看，哪些金融资产可以持续增长？</li><li>什么是投资的大道？如何成为优秀投资人？</li><li>价值投资在中国是否适用？</li></ol><h2 id="第一部分-资产管理行业的道德底线" tabindex="-1">第一部分：资产管理行业的道德底线 <a class="header-anchor" href="#第一部分-资产管理行业的道德底线" aria-label="Permalink to &quot;第一部分：资产管理行业的道德底线&quot;">​</a></h2><h3 id="行业的两个独特性" tabindex="-1">行业的两个独特性 <a class="header-anchor" href="#行业的两个独特性" aria-label="Permalink to &quot;行业的两个独特性&quot;">​</a></h3><h4 id="独特性一-用户无法判断产品好坏" tabindex="-1">独特性一：用户无法判断产品好坏 <a class="header-anchor" href="#独特性一-用户无法判断产品好坏" aria-label="Permalink to &quot;独特性一：用户无法判断产品好坏&quot;">​</a></h4><p><strong>与其他行业的对比</strong>：</p><table tabindex="0"><thead><tr><th>行业</th><th>用户判断方式</th></tr></thead><tbody><tr><td>汽车</td><td>驾驶体验</td></tr><tr><td>餐饮</td><td>用餐体验</td></tr><tr><td>酒店</td><td>入住体验</td></tr><tr><td>服装</td><td>穿着体验</td></tr><tr><td><strong>资产管理</strong></td><td><strong>几乎无法判断</strong></td></tr></tbody></table><p><strong>为什么无法判断？</strong></p><ol><li><strong>时间滞后</strong>：需要5-10年才能判断</li><li><strong>结果混杂</strong>：运气与能力难以区分</li><li><strong>信息不对称</strong>：用户不懂投资逻辑</li><li><strong>业绩波动</strong>：短期业绩充满噪音</li></ol><p><strong>后果</strong>：</p><blockquote><p><strong>正是因为没有办法判断（产品和服务的优劣），所以绝大部分理论都和屁股决定脑袋有关。</strong></p></blockquote><h4 id="独特性二-报酬与贡献脱节" tabindex="-1">独特性二：报酬与贡献脱节 <a class="header-anchor" href="#独特性二-报酬与贡献脱节" aria-label="Permalink to &quot;独特性二：报酬与贡献脱节&quot;">​</a></h4><p><strong>收费模式的问题</strong>：</p><table tabindex="0"><thead><tr><th>收费方式</th><th>问题</th></tr></thead><tbody><tr><td>按比例收费</td><td>不管盈亏都收费</td></tr><tr><td>2+20模式</td><td>赚钱提成，亏钱不赔</td></tr><tr><td>指数基金对比</td><td>业绩差也能收费</td></tr></tbody></table><p><strong>结果</strong>：</p><ul><li>行业报酬远高于其他行业</li><li>实际贡献往往有限</li><li>定价反映从业者利益，而非客户利益</li></ul><h3 id="两条道德底线" tabindex="-1">两条道德底线 <a class="header-anchor" href="#两条道德底线" aria-label="Permalink to &quot;两条道德底线&quot;">​</a></h3><h4 id="底线一-追求真知是道德责任" tabindex="-1">底线一：追求真知是道德责任 <a class="header-anchor" href="#底线一-追求真知是道德责任" aria-label="Permalink to &quot;底线一：追求真知是道德责任&quot;">​</a></h4><blockquote><p><strong>把对真知、智慧的追求当作是自己的道德责任，要有意识地杜绝一切屁股决定脑袋的理论。</strong></p></blockquote><p><strong>具体要求</strong>：</p><ol><li>持续学习，追求真理</li><li>不被利益左右判断</li><li>不散布对自己有利的谬论</li><li>不被似是而非的理论蛊惑</li></ol><p><strong>为什么重要？</strong></p><p>投资行业充满：</p><ul><li>似是而非的观点</li><li>屁股决定脑袋的理论</li><li>复杂的判断和预测</li></ul><p>如果没有追求真知的责任感，很容易自欺欺人，最终害人害己。</p><h4 id="底线二-建立受托人责任" tabindex="-1">底线二：建立受托人责任 <a class="header-anchor" href="#底线二-建立受托人责任" aria-label="Permalink to &quot;底线二：建立受托人责任&quot;">​</a></h4><blockquote><p><strong>客户给你的每一分钱，你都把它看作是自己的父母辛勤劳动、勤俭节省、积攒了一辈子、交到你手上去打理的钱。</strong></p></blockquote><p><strong>受托人责任（Fiduciary Duty）的内涵</strong>：</p><ul><li>把客户利益置于自身利益之上</li><li>像对待父母的钱一样对待客户的钱</li><li>建立长期的信任关系</li><li>为客户创造真正的价值</li></ul><p><strong>先天基因论</strong>：</p><blockquote><p><strong>受托人责任这个概念，我认为多多少少有些先天的基因在里面。我所了解的人里或者有这个基因，或者没有这个基因。</strong></p></blockquote><p><strong>警示</strong>：</p><blockquote><p><strong>没有这种基因的人，以后无论用什么方式，基本上都没有办法让他有。如果你的钱交到这些人手里，那真是巨大的悲剧。</strong></p></blockquote><h2 id="第二部分-长期财富增长的真相" tabindex="-1">第二部分：长期财富增长的真相 <a class="header-anchor" href="#第二部分-长期财富增长的真相" aria-label="Permalink to &quot;第二部分：长期财富增长的真相&quot;">​</a></h2><h3 id="_200年资产回报数据" tabindex="-1">200年资产回报数据 <a class="header-anchor" href="#_200年资产回报数据" aria-label="Permalink to &quot;200年资产回报数据&quot;">​</a></h3><p><strong>数据来源</strong>：宾州大学沃顿商学院西格尔教授（Jeremy Siegel）</p><p><strong>美国1802-2022年大类资产表现</strong>：</p><table tabindex="0"><thead><tr><th>资产类别</th><th>200年后价值（扣除通胀）</th><th>年化回报</th></tr></thead><tbody><tr><td>现金</td><td>0.05美元</td><td>-1.4%</td></tr><tr><td>黄金</td><td>3.12美元</td><td>0.5%</td></tr><tr><td>短期债券</td><td>275美元</td><td>2.7%</td></tr><tr><td>长期债券</td><td>1,600美元</td><td>3.6%</td></tr><tr><td><strong>股票</strong></td><td><strong>1,030,000美元</strong></td><td><strong>6.7%</strong></td></tr></tbody></table><p><img src="'+i+'" alt="美国自1801年至今大类资产的回报表现"><em>图7：美国自1801年至今大类资产的回报表现（来源：Siegel, Jeremy, Future for Investors, 2005）</em></p><h3 id="为什么差距如此巨大" tabindex="-1">为什么差距如此巨大？ <a class="header-anchor" href="#为什么差距如此巨大" aria-label="Permalink to &quot;为什么差距如此巨大？&quot;">​</a></h3><h4 id="原因一-通货膨胀" tabindex="-1">原因一：通货膨胀 <a class="header-anchor" href="#原因一-通货膨胀" aria-label="Permalink to &quot;原因一：通货膨胀&quot;">​</a></h4><p><strong>现金的贬值</strong>：</p><ul><li>200年平均通胀率：1.4%/年</li><li>1美元 → 0.05美元（购买力）</li><li>丢失了95%的价值</li></ul><p><strong>数学解释</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(1 - 0.014)^200 ≈ 0.06</span></span></code></pre></div><h4 id="原因二-经济增长" tabindex="-1">原因二：经济增长 <a class="header-anchor" href="#原因二-经济增长" aria-label="Permalink to &quot;原因二：经济增长&quot;">​</a></h4><p><strong>GDP增长</strong>：</p><ul><li>200年增长约33,000倍</li><li>年化增长率约3%</li></ul><p><strong>股票与GDP的关系</strong>：</p><ol><li>GDP增长 → 公司销售额增长</li><li>销售额增长 → 利润增长（成本相对固定）</li><li>利润增长 → 股票价值增长</li><li>平均市盈率15倍 → 每股收益约6.7%</li></ol><p><strong>复利的力量</strong>：</p><blockquote><p><strong>爱因斯坦把复利称之为世界第八大奇迹是有道理的。</strong></p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1.067^200 ≈ 1,030,000</span></span></code></pre></div><h2 id="第三部分-价值投资的四大理念" tabindex="-1">第三部分：价值投资的四大理念 <a class="header-anchor" href="#第三部分-价值投资的四大理念" aria-label="Permalink to &quot;第三部分：价值投资的四大理念&quot;">​</a></h2><h3 id="理念一-股票是公司的部分所有权" tabindex="-1">理念一：股票是公司的部分所有权 <a class="header-anchor" href="#理念一-股票是公司的部分所有权" aria-label="Permalink to &quot;理念一：股票是公司的部分所有权&quot;">​</a></h3><p><strong>核心观点</strong>：</p><blockquote><p><strong>股票不仅仅是可以买卖的证券，实际上代表的是对公司所有权的证书，是对公司的部分所有权。</strong></p></blockquote><p><strong>为什么重要？</strong></p><table tabindex="0"><thead><tr><th>视角</th><th>理解</th></tr></thead><tbody><tr><td>投机者</td><td>股票是交易筹码</td></tr><tr><td><strong>价值投资者</strong></td><td><strong>股票是公司所有权</strong></td></tr></tbody></table><p><strong>正道 vs 邪道</strong>：</p><ul><li><strong>正道</strong>：投资帮助公司增长，分享应得的收益</li><li><strong>邪道</strong>：零和博弈，从他人损失中获利</li></ul><p><strong>可持续性的检验</strong>：</p><blockquote><p><strong>如果把赚钱的方法一点一滴毫无保留告诉所有的人，大家都觉得你这个赚钱的方法真对，真好，我佩服，这就是可持续的。这就叫大道，这就叫正道。</strong></p></blockquote><h3 id="理念二-市场是为投资者服务的" tabindex="-1">理念二：市场是为投资者服务的 <a class="header-anchor" href="#理念二-市场是为投资者服务的" aria-label="Permalink to &quot;理念二：市场是为投资者服务的&quot;">​</a></h3><p><strong>核心观点</strong>：</p><blockquote><p><strong>市场的存在只是为你而服务的。能够给你提供机会，让你去购买所有权，也会给你个机会，在你很多年之后需要钱的时候，能够把它出让，变成现金。</strong></p></blockquote><p><strong>正确理解市场</strong>：</p><table tabindex="0"><thead><tr><th>错误理解</th><th>正确理解</th></tr></thead><tbody><tr><td>市场是老师</td><td>市场是工具</td></tr><tr><td>市场总是对的</td><td>市场经常犯错</td></tr><tr><td>跟随市场</td><td>利用市场</td></tr><tr><td>价格=价值</td><td>价格≠价值</td></tr></tbody></table><p><strong>与95%市场参与者的区别</strong>：</p><blockquote><p><strong>这个市场从来都不能告诉你，真正的价值是什么。它只能告诉你的只是价格是什么，你不能把市场当作你的老师，你只能把它当作一个可以利用的工具。</strong></p></blockquote><h3 id="理念三-安全边际" tabindex="-1">理念三：安全边际 <a class="header-anchor" href="#理念三-安全边际" aria-label="Permalink to &quot;理念三：安全边际&quot;">​</a></h3><p><strong>核心观点</strong>：</p><blockquote><p><strong>投资的本质是对未来进行预测，而预测得到的结果不可能百分之百准确，只能是从零到接近一百。那么当我们做判断的时候，就必须要预留很大的空间，叫安全边际。</strong></p></blockquote><p><strong>为什么需要安全边际？</strong></p><ol><li><strong>预测的不确定性</strong>：没有人能100%预测未来</li><li><strong>错误的缓冲</strong>：即使预测错误，也不会损失太多</li><li><strong>正确时的超额回报</strong>：预测正确时，回报更高</li></ol><p><strong>实践要求</strong>：</p><blockquote><p><strong>你的买入价格一定要大大低于公司的内在价值。</strong></p></blockquote><p><strong>安全边际的计算</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>安全边际 = 内在价值 - 市场价格</span></span></code></pre></div><h3 id="理念四-能力圈" tabindex="-1">理念四：能力圈 <a class="header-anchor" href="#理念四-能力圈" aria-label="Permalink to &quot;理念四：能力圈&quot;">​</a></h3><p><strong>巴菲特的独特贡献</strong>：</p><blockquote><p><strong>投资人可以通过长期不懈的努力，真正建立起自己的能力圈，能够对某些公司、某些行业获得比几乎所有人更深的理解，而且能够对公司未来长期的表现，做出比所有其他人更准确的判断。</strong></p></blockquote><p><strong>能力圈的核心：边界</strong></p><blockquote><p><strong>没有边界的能力就不是真的能力。如果你有一个观点，你必须要能够告诉我这个观点不成立的条件，这时它才是一个真正的观点。</strong></p></blockquote><p><strong>市场先生的作用</strong>：</p><blockquote><p><strong>市场存在的目的是什么？对于市场参与者而言，市场存在的目的就是发现人性的弱点。</strong></p></blockquote><p><strong>真正的风险</strong>：</p><blockquote><p><strong>只有在这个意义上投资才真正是有风险的，这个风险不是股票价格的上上下下，而是资本永久性地丢失，这才是真正的风险。</strong></p></blockquote><h2 id="第四部分-为什么价值投资是大道却人迹罕至" tabindex="-1">第四部分：为什么价值投资是大道却人迹罕至？ <a class="header-anchor" href="#第四部分-为什么价值投资是大道却人迹罕至" aria-label="Permalink to &quot;第四部分：为什么价值投资是大道却人迹罕至？&quot;">​</a></h2><h3 id="大道的特征" tabindex="-1">大道的特征 <a class="header-anchor" href="#大道的特征" aria-label="Permalink to &quot;大道的特征&quot;">​</a></h3><p><strong>为什么价值投资是大道？</strong></p><ol><li><strong>逻辑简单清晰</strong>：四个理念，易于理解</li><li><strong>经过长期验证</strong>：巴菲特57年业绩</li><li><strong>可持续可复制</strong>：方法可以传授学习</li><li><strong>多方共赢</strong>：帮助公司、客户、自己</li></ol><h3 id="为什么走的人很少" tabindex="-1">为什么走的人很少？ <a class="header-anchor" href="#为什么走的人很少" aria-label="Permalink to &quot;为什么走的人很少？&quot;">​</a></h3><h4 id="原因一-太慢" tabindex="-1">原因一：太慢 <a class="header-anchor" href="#原因一-太慢" aria-label="Permalink to &quot;原因一：太慢&quot;">​</a></h4><blockquote><p><strong>康庄大道非常慢。听起来能走到头，但实际上很慢。</strong></p></blockquote><p><strong>时间成本</strong>：</p><ul><li>买入后可能长期不涨</li><li>市场不理性的时间可能很长</li><li>需要等待价值回归</li></ul><h4 id="原因二-太难" tabindex="-1">原因二：太难 <a class="header-anchor" href="#原因二-太难" aria-label="Permalink to &quot;原因二：太难&quot;">​</a></h4><p><strong>预测未来的困难</strong>：</p><blockquote><p><strong>投资的本事是对未来进行预测，真正要理解一个公司、一个行业，要能够去判断它未来5年、10年的情况。</strong></p></blockquote><p><strong>能力圈建立的难度</strong>：</p><ul><li>需要多年不懈努力</li><li>需要刻苦学习</li><li>圈开始时非常狭小</li></ul><h4 id="原因三-短期诱惑" tabindex="-1">原因三：短期诱惑 <a class="header-anchor" href="#原因三-短期诱惑" aria-label="Permalink to &quot;原因三：短期诱惑&quot;">​</a></h4><blockquote><p><strong>市场总是让你感觉到短期可以获利——你短期的资产确确实实可以有巨大的变化，所以这会给你幻觉，让你想象在短期里可以获得巨大利益。</strong></p></blockquote><p><strong>旁门左道的吸引力</strong>：</p><ul><li>短期暴利的可能性</li><li>成为&quot;股神&quot;的幻觉</li><li>快速致富的梦想</li></ul><h4 id="原因四-需要诚实" tabindex="-1">原因四：需要诚实 <a class="header-anchor" href="#原因四-需要诚实" aria-label="Permalink to &quot;原因四：需要诚实&quot;">​</a></h4><blockquote><p><strong>做这个行业最根本的要求，是一定要在知识上做彻彻底底、百分之百诚实的人。</strong></p></blockquote><p><strong>自欺欺人的陷阱</strong>：</p><ul><li>屁股决定脑袋</li><li>假话说多了自己都信</li><li>难以承认错误</li></ul><h3 id="时间的要求" tabindex="-1">时间的要求 <a class="header-anchor" href="#时间的要求" aria-label="Permalink to &quot;时间的要求&quot;">​</a></h3><blockquote><p><strong>在这个行业里，要在很长时间持续不断地艰苦地工作，才有可能真正地成才，这个时间恐怕要15年以上。</strong></p></blockquote><p><strong>成才的标准</strong>：</p><ul><li>连续15年以上优异成绩</li><li>在正确的道路上研究</li><li>能力远远大于运气</li></ul><h2 id="第五部分-价值投资在中国是否适用" tabindex="-1">第五部分：价值投资在中国是否适用？ <a class="header-anchor" href="#第五部分-价值投资在中国是否适用" aria-label="Permalink to &quot;第五部分：价值投资在中国是否适用？&quot;">​</a></h2><h3 id="核心问题" tabindex="-1">核心问题 <a class="header-anchor" href="#核心问题" aria-label="Permalink to &quot;核心问题&quot;">​</a></h3><p><strong>质疑的声音</strong>：</p><ul><li>中国是不是特殊？</li><li>价值投资是否只适合美国？</li><li>中国市场是否太投机？</li></ul><h3 id="李录的回答" tabindex="-1">李录的回答 <a class="header-anchor" href="#李录的回答" aria-label="Permalink to &quot;李录的回答&quot;">​</a></h3><p><strong>第一，3.0文明的普适性</strong>：</p><blockquote><p><strong>3.0文明的本质是什么呢？就是在这个时期，由于种种的原因，出现了现代科技和自由市场经济，这两者的结合形成了我们看到的3.0文明。</strong></p></blockquote><p><strong>第二，中国已经在市场体系中</strong>：</p><blockquote><p><strong>中国在1990年代以后，就已经全面进入到全球大的自由市场体系里了。</strong></p></blockquote><p><strong>第三，价值投资的基本逻辑不变</strong>：</p><ul><li>股票代表公司所有权 ✓</li><li>市场可以为你所用 ✓</li><li>需要安全边际 ✓</li><li>需要能力圈 ✓</li></ul><h3 id="中国的特殊性" tabindex="-1">中国的特殊性 <a class="header-anchor" href="#中国的特殊性" aria-label="Permalink to &quot;中国的特殊性&quot;">​</a></h3><p><strong>确实存在差异</strong>：</p><ul><li>市场成熟度不同</li><li>投资者结构不同</li><li>监管环境不同</li><li>文化背景不同</li></ul><p><strong>但核心机制相同</strong>：</p><ul><li>经济持续增长</li><li>优秀公司创造价值</li><li>价格围绕价值波动</li><li>长期看价值回归</li></ul><h2 id="第六部分-实战应用与常见陷阱" tabindex="-1">第六部分：实战应用与常见陷阱 <a class="header-anchor" href="#第六部分-实战应用与常见陷阱" aria-label="Permalink to &quot;第六部分：实战应用与常见陷阱&quot;">​</a></h2><h3 id="建立正确的投资流程" tabindex="-1">建立正确的投资流程 <a class="header-anchor" href="#建立正确的投资流程" aria-label="Permalink to &quot;建立正确的投资流程&quot;">​</a></h3><p><strong>第一步：道德自律</strong></p><ul><li>追求真知</li><li>建立受托人责任</li></ul><p><strong>第二步：资产配置</strong></p><ul><li>长期看，股票是最佳资产</li><li>避免现金的长期持有</li></ul><p><strong>第三步：选择投资方法</strong></p><ul><li>走价值投资大道</li><li>避开旁门左道</li></ul><p><strong>第四步：建立能力圈</strong></p><ul><li>选择能理解的行业</li><li>深入研究少数公司</li><li>明确能力边界</li></ul><p><strong>第五步：严格执行</strong></p><ul><li>等待安全边际</li><li>长期持有</li><li>不理会市场波动</li></ul><h3 id="常见陷阱" tabindex="-1">常见陷阱 <a class="header-anchor" href="#常见陷阱" aria-label="Permalink to &quot;常见陷阱&quot;">​</a></h3><h4 id="陷阱一-短期业绩焦虑" tabindex="-1">陷阱一：短期业绩焦虑 <a class="header-anchor" href="#陷阱一-短期业绩焦虑" aria-label="Permalink to &quot;陷阱一：短期业绩焦虑&quot;">​</a></h4><p><strong>表现</strong>：</p><ul><li>频繁查看账户</li><li>被短期波动影响</li><li>追逐热点</li></ul><p><strong>解决</strong>：</p><ul><li>降低查看频率</li><li>关注长期价值</li><li>建立投资纪律</li></ul><h4 id="陷阱二-能力圈幻觉" tabindex="-1">陷阱二：能力圈幻觉 <a class="header-anchor" href="#陷阱二-能力圈幻觉" aria-label="Permalink to &quot;陷阱二：能力圈幻觉&quot;">​</a></h4><p><strong>表现</strong>：</p><ul><li>认为自己什么都懂</li><li>频繁更换投资领域</li><li>追逐热门行业</li></ul><p><strong>解决</strong>：</p><ul><li>承认无知</li><li>专注少数领域</li><li>明确说&quot;不&quot;</li></ul><h4 id="陷阱三-安全边际不足" tabindex="-1">陷阱三：安全边际不足 <a class="header-anchor" href="#陷阱三-安全边际不足" aria-label="Permalink to &quot;陷阱三：安全边际不足&quot;">​</a></h4><p><strong>表现</strong>：</p><ul><li>追高买入</li><li>过度乐观</li><li>忽视风险</li></ul><p><strong>解决</strong>：</p><ul><li>保守估值</li><li>耐心等待</li><li>分散投资</li></ul><h4 id="陷阱四-缺乏耐心" tabindex="-1">陷阱四：缺乏耐心 <a class="header-anchor" href="#陷阱四-缺乏耐心" aria-label="Permalink to &quot;陷阱四：缺乏耐心&quot;">​</a></h4><p><strong>表现</strong>：</p><ul><li>频繁交易</li><li>过早卖出</li><li>追逐短期机会</li></ul><p><strong>解决</strong>：</p><ul><li>降低交易频率</li><li>延长持有期</li><li>相信复利</li></ul><h2 id="本章总结" tabindex="-1">本章总结 <a class="header-anchor" href="#本章总结" aria-label="Permalink to &quot;本章总结&quot;">​</a></h2><h3 id="核心要点回顾" tabindex="-1">核心要点回顾 <a class="header-anchor" href="#核心要点回顾" aria-label="Permalink to &quot;核心要点回顾&quot;">​</a></h3><ol><li><strong>行业道德底线</strong>：追求真知、受托人责任</li><li><strong>长期资产表现</strong>：股票200年增值100万倍</li><li><strong>价值投资四理念</strong>：所有权、市场工具、安全边际、能力圈</li><li><strong>大道人迹罕至</strong>：太慢、太难、短期诱惑、需要诚实</li><li><strong>中国同样适用</strong>：3.0文明普适，中国已在市场体系中</li></ol><h3 id="关键公式" tabindex="-1">关键公式 <a class="header-anchor" href="#关键公式" aria-label="Permalink to &quot;关键公式&quot;">​</a></h3><ul><li><strong>复利公式</strong>：时间 × 收益率 = 巨大差异</li><li><strong>安全边际</strong>：内在价值 - 市场价格</li><li><strong>能力圈边界</strong>：能说清楚什么情况下观点错误</li></ul><h3 id="关键术语" tabindex="-1">关键术语 <a class="header-anchor" href="#关键术语" aria-label="Permalink to &quot;关键术语&quot;">​</a></h3><ul><li><strong>受托人责任</strong>：把客户利益置于自身之上的道德义务</li><li><strong>安全边际</strong>：预留的预测错误缓冲空间</li><li><strong>能力圈</strong>：通过长期努力建立的深度理解领域</li><li><strong>市场先生</strong>：市场的非理性特征比喻</li></ul><h3 id="延伸思考" tabindex="-1">延伸思考 <a class="header-anchor" href="#延伸思考" aria-label="Permalink to &quot;延伸思考&quot;">​</a></h3><ol><li>如何检验自己是否有受托人责任的基因？</li><li>你的能力圈边界在哪里？</li><li>为什么明知是大道，却难以坚持？</li><li>在中国市场实践价值投资的具体挑战？</li></ol><h3 id="下章预告" tabindex="-1">下章预告 <a class="header-anchor" href="#下章预告" aria-label="Permalink to &quot;下章预告&quot;">​</a></h3><p>下一讲《价值投资的知行合一》，我们将深入探讨李录2019年在北大光华的演讲，了解如何在实践中贯彻价值投资理念，以及&quot;知行合一&quot;的具体含义。</p><hr><p><em>本文基于李录《文明、现代化、价值投资与中国》下篇演讲整理。</em></p>',182)])])}const c=l(e,[["render",n]]);export{b as __pageData,c as default};
